    Restituisce i valori del record, con la possibilità di filtrare per includere solo determinati valori in base all'indice o alla chiave.

    :param keys: indici o chiavi degli elementi da includere; se non viene fornito nessun parametro, verranno inclusi tutti i valori
    :return: lista di valori
    :rtype: list
    """
    if not keys:
        # Se non sono specificate chiavi, restituisce tutti i valori
        return list(self._values)

    result = []
    for key in keys:
        if isinstance(key, int):
            # Se la chiave è un indice numerico
            if 0 <= key < len(self._values):
                result.append(self._values[key])
        else:
            # Se la chiave è una stringa
            try:
                index = self._fields.index(key)
                result.append(self._values[index])
            except ValueError:
                pass

    return result

def data(self, *keys):
    if not keys:
        # If no keys specified, return all fields
        return dict(zip(self.keys(), self.values()))

    result = {}
    for key in keys:
        if isinstance(key, int):
            # Handle numeric index
            try:
                field_name = self.keys()[key]
                result[field_name] = self.values()[key]
            except IndexError:
                raise IndexError(f"Index {key} is out of bounds")
        else:
            # Handle field name
            result[key] = self[key] if key in self else None

    return result

def pop_u16(self):
    if len(self.data) < 2:
        raise ValueError("Not enough bytes to pop u16")
    value = (self.data[-2] << 8) | self.data[-1]  # Combine bytes in big-endian order
    self.data = self.data[:-2]  # Remove last 2 bytes
    return value

