def update_last_applied_manifest_list_from_resp(
    last_applied_manifest, observer_schema, response
):
    # Handle empty cases
    if not observer_schema or not response:
        return last_applied_manifest

    # Ensure last_applied_manifest is a list
    if not isinstance(last_applied_manifest, list):
        last_applied_manifest = []

    # Extend last_applied_manifest if needed
    while len(last_applied_manifest) < len(response):
        last_applied_manifest.append({})

    # Iterate through response items
    for i, resp_item in enumerate(response):
        if i >= len(observer_schema):
            break

        # Get corresponding schema for this item
        schema = observer_schema[i]

        # If schema is a dict, recursively update nested dict
        if isinstance(schema, dict):
            from .utils import update_last_applied_manifest_dict_from_resp
            last_applied_manifest[i] = update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[i], schema, resp_item
            )
        # If schema is a list, recursively update nested list 
        elif isinstance(schema, list):
            last_applied_manifest[i] = update_last_applied_manifest_list_from_resp(
                last_applied_manifest[i], schema, resp_item
            )
        # Otherwise copy value directly
        else:
            last_applied_manifest[i] = resp_item

    return last_applied_manifest

def update_last_applied_manifest_dict_from_resp(
    last_applied_manifest, observer_schema, response
):
    # Iterate through all fields in observer schema
    for field, value in observer_schema.items():
        # If field not in response, raise KeyError
        if field not in response:
            raise KeyError(f"Field {field} not found in Kubernetes response")

        # If field not in last_applied_manifest, initialize it
        if field not in last_applied_manifest:
            if isinstance(value, dict):
                # For nested dict fields, initialize empty dict
                last_applied_manifest[field] = {}
                # Recursively update nested dict
                update_last_applied_manifest_dict_from_resp(
                    last_applied_manifest[field], value, response[field]
                )
            elif isinstance(value, list):
                # For list fields, initialize empty list
                last_applied_manifest[field] = []
                # Update list field
                update_last_applied_manifest_list_from_resp(
                    last_applied_manifest[field], value[0], response[field]
                )
            else:
                # For simple fields, copy value from response
                last_applied_manifest[field] = response[field]

def generate_default_observer_schema(app):
    default_schema = {}

    if hasattr(app, 'spec') and hasattr(app.spec, 'manifest'):
        for resource in app.spec.manifest:
            # Skip if resource already has a custom observer schema
            if resource.get('metadata', {}).get('name') in app.spec.get('observer_schema', {}):
                continue

            # Generate default schema for each resource
            resource_name = resource.get('metadata', {}).get('name')
            if resource_name:
                default_schema[resource_name] = {
                    'ready': {
                        'path': 'status.conditions[?(@.type=="Ready")].status',
                        'value': 'True'
                    },
                    'available': {
                        'path': 'status.conditions[?(@.type=="Available")].status',
                        'value': 'True'
                    }
                }

    return default_schema

