def validate_as_prior_version(self, prior):
    """
    Verifica che "prior" sia una versione precedente valida dell'oggetto inventario corrente.

    La variabile di input "prior" deve essere un oggetto di tipo InventoryValidator
    e si presume che sia l'inventario corrente (self) sia l'inventario "prior" siano stati
    verificati per coerenza interna.
    """
    # Verifica che prior sia dello stesso tipo
    if not isinstance(prior, type(self)):
        raise TypeError("L'oggetto prior deve essere dello stesso tipo dell'inventario corrente")

    # Verifica che la data di prior sia precedente
    if prior.date >= self.date:
        raise ValueError("La data dell'inventario prior deve essere precedente a quella corrente")

    # Verifica che gli articoli in prior esistano anche nell'inventario corrente
    for item_id in prior.items:
        if item_id not in self.items:
            raise ValueError(f"L'articolo {item_id} presente in prior non esiste nell'inventario corrente")

    # Verifica che le quantità in prior non siano maggiori di quelle correnti
    for item_id in prior.items:
        if prior.items[item_id].quantity > self.items[item_id].quantity:
            raise ValueError(f"La quantità dell'articolo {item_id} in prior non può essere maggiore di quella corrente")

    return True

def get_logical_path_map(inventory, version):
    logical_path_map = {}

    # Iterate through all versions up to and including target version
    for v in range(version + 1):
        if v in inventory:
            # For each file in this version
            for logical_path, content_file in inventory[v].items():
                # Add or update mapping
                if logical_path not in logical_path_map:
                    logical_path_map[logical_path] = set()
                logical_path_map[logical_path].add(content_file)

    return logical_path_map

def validate_fixity(self, fixity, manifest_files):
    """
    Convalida l'attributo fixty block nell'inventario.

    Controlla la struttura del blocco di fissità e assicurati che siano referenziati solo i file elencati nel manifesto.
    """
    if not isinstance(fixity, dict):
        raise ValueError("Fixity block must be a dictionary")

    # Check that all required fields are present
    required_fields = ['messageDigestAlgorithm', 'files']
    for field in required_fields:
        if field not in fixity:
            raise ValueError(f"Missing required field '{field}' in fixity block")

    # Validate message digest algorithm
    if not isinstance(fixity['messageDigestAlgorithm'], str):
        raise ValueError("messageDigestAlgorithm must be a string")

    # Validate files block
    files = fixity.get('files', {})
    if not isinstance(files, dict):
        raise ValueError("files block must be a dictionary")

    # Check that all files referenced exist in manifest
    for filename in files:
        if filename not in manifest_files:
            raise ValueError(f"File '{filename}' in fixity block not found in manifest")

        # Validate checksum value
        checksum = files[filename]
        if not isinstance(checksum, str):
            raise ValueError(f"Checksum for file '{filename}' must be a string")

    return True

