def validate_hierarchy(self, validate_objects=True, check_digests=True, show_warnings=False):
    """
    Valida la gerarchia di archiviazione.

    Restituisce:
        num_objects - numero di oggetti verificati
        good_objects - numero di oggetti verificati che sono risultati validi
    """
    num_objects = 0
    good_objects = 0

    # Attraversa ricorsivamente la gerarchia
    for root, dirs, files in self.walk():
        for file in files:
            num_objects += 1

            # Verifica l'oggetto se richiesto
            if validate_objects:
                try:
                    # Verifica il digest se richiesto
                    if check_digests:
                        if self.verify_digest(file):
                            good_objects += 1
                    else:
                        # Se non verifichiamo i digest, consideriamo valido l'oggetto
                        good_objects += 1
                except Exception as e:
                    if show_warnings:
                        print(f"Warning: Failed to validate {file}: {str(e)}")
            else:
                # Se non verifichiamo gli oggetti, li consideriamo tutti validi
                good_objects += 1

    return num_objects, good_objects

def next_version(version):
    # Split version into parts
    parts = version.split('.')

    # Convert to integers
    nums = [int(x) for x in parts]

    # Start from rightmost digit
    i = len(nums) - 1

    while i >= 0:
        # If current digit is 9, set to 0 and continue carrying
        if nums[i] == 9:
            nums[i] = 0
            i -= 1
        # Otherwise increment digit and break
        else:
            nums[i] += 1
            break

    # If we carried through all digits, add new digit 1 at start
    if i < 0:
        nums.insert(0, 1)

    # Convert back to strings, preserving leading zeros
    result = []
    for i, num in enumerate(nums):
        # Keep leading zeros if original had them
        if parts[i].startswith('0') and num != 0:
            result.append('0' + str(num))
        elif parts[i].startswith('0'):
            result.append('0' + str(num))
        else:
            result.append(str(num))

    return '.'.join(result)

def validate_version_inventories(self, version_dirs):
    """
    Ogni versione DOVREBBE avere un inventario fino a quel punto.
    Inoltre, tieni traccia di eventuali digest di contenuto diversi da quelli
    presenti nell'inventario principale, in modo da poterli verificare
    anche durante la validazione del contenuto.

    version_dirs è un array di nomi di directory di versione e si presume
      che sia in sequenza di versione (1, 2, 3...).
    """
    content_digests = set()

    # Validate each version has an inventory
    for version in version_dirs:
        inventory_path = os.path.join(version, "inventory.txt")
        if not os.path.exists(inventory_path):
            raise ValidationError(f"Missing inventory file for version {version}")

        # Read inventory and collect content digests
        with open(inventory_path) as f:
            inventory = f.readlines()

        for line in inventory:
            if line.strip():
                try:
                    filename, digest = line.strip().split()
                    content_digests.add(digest)
                except ValueError:
                    raise ValidationError(f"Invalid inventory line in {version}: {line}")

    # Compare with main inventory
    main_inventory_path = "inventory.txt"
    if os.path.exists(main_inventory_path):
        with open(main_inventory_path) as f:
            main_inventory = f.readlines()

        main_digests = set()
        for line in main_inventory:
            if line.strip():
                try:
                    filename, digest = line.strip().split()
                    main_digests.add(digest)
                except ValueError:
                    raise ValidationError(f"Invalid line in main inventory: {line}")

        # Check for digests not in main inventory
        diff_digests = content_digests - main_digests
        if diff_digests:
            self.extra_digests = diff_digests

    return True

def find_path_type(path):
    import os

    # Check if path exists
    if not os.path.exists(path):
        return "Path does not exist"

    # Check if it's a directory
    if not os.path.isdir(path):
        if os.path.isfile(path):
            return "file"
        return "Path is not a directory"

    # Look for Namaste files starting with "0="
    namaste_files = [f for f in os.listdir(path) if f.startswith("0=")]

    if not namaste_files:
        return "No Namaste files found"

    # Check content of first Namaste file found
    namaste_content = ""
    try:
        with open(os.path.join(path, namaste_files[0]), 'r') as f:
            namaste_content = f.read().strip()
    except:
        return "Error reading Namaste file"

    # Check content to determine type
    if "ocfl_" in namaste_content.lower():
        if "root" in namaste_content.lower():
            return "root"
        elif "object" in namaste_content.lower():
            return "object"

    return f"Unknown Namaste content: {namaste_content}"

def amend_bzparams(self, params, bug_ids):
