        params = {}

    # Convert single bug ID to list if needed
    if isinstance(bug_ids, (int, str)):
        bug_ids = [str(bug_ids)]
    elif bug_ids:
        bug_ids = [str(bug_id) for bug_id in bug_ids]

    # Add bug IDs to parameters if provided
    if bug_ids:
        params['ids'] = bug_ids

    # Ensure include_fields is a list
