def hist_to_graph(hist, make_value=None, get_coordinate="left",
                  field_names=("x", "y"), scale=None):

    # Default make_value function just returns bin content
    if make_value is None:
        make_value = lambda x: x

    # Get coordinate mapping functions
    coordinate_funcs = {
        "left": lambda bin_: bin_.edges[0],
        "right": lambda bin_: bin_.edges[1], 
        "middle": lambda bin_: (bin_.edges[0] + bin_.edges[1])/2
    }

    get_coord = coordinate_funcs[get_coordinate]

    # Create points list
    points = []
    for bin_ in hist:
        x = get_coord(bin_)
        y = make_value(bin_.value)

        # Handle single values vs tuples
        if isinstance(y, tuple):
            points.append((x,) + y)
        else:
            points.append((x, y))

    # Set scale if requested
    if scale is True:
        scale = hist.scale

    # Create field names based on number of values
    if len(points[0]) != len(field_names):
        raise ValueError("Number of field names must match number of values per point")

    # Import Graph class and create new graph
    from .graph import Graph
    return Graph(points, field_names=field_names, scale=scale)

def _verify(iface, candidate, tentative=False, vtype=None):
    from zope.interface.exceptions import Invalid
    from zope.interface.interface import Method
    from collections import defaultdict

    errors = defaultdict(list)

    # Check if candidate claims to provide interface
    if not tentative and not iface.providedBy(candidate):
        errors['provide'].append(
            f"{candidate!r} does not provide interface {iface!r}"
        )

    # Check methods
    for name, desc in iface.namesAndDescriptions(all=True):
        if not isinstance(desc, Method):
            # Skip non-method attributes for now
            continue

        # Check if method exists
        try:
            meth = getattr(candidate, name)
        except AttributeError:
            errors['methods'].append(
                f"The {name!r} method was not provided"
            )
            continue

        # Verify method signature if possible
        if hasattr(desc, 'getSignatureInfo'):
            sig_info = desc.getSignatureInfo()
            try:
                candidate_sig = desc.getSignatureInfo(meth)

                # Compare signatures
                if sig_info['positional'] != candidate_sig['positional'] or \
                   sig_info['required'] != candidate_sig['required'] or \
                   sig_info['optional'] != candidate_sig['optional'] or \
                   sig_info['varargs'] != candidate_sig['varargs'] or \
                   sig_info['kwargs'] != candidate_sig['kwargs']:
                    errors['signatures'].append(
                        f"The {name!r} method has incorrect signature"
                    )
            except (TypeError, ValueError):
                errors['signatures'].append(
                    f"Could not verify signature of {name!r} method"
                )

    # Check attributes
    for name, desc in iface.namesAndDescriptions(all=True):
        if isinstance(desc, Method):
            continue

        if not hasattr(candidate, name):
            errors['attributes'].append(
                f"The {name!r} attribute was not provided" 
            )

    # If we have errors, raise them
    if errors:
        if sum(len(v) for v in errors.values()) == 1:
            # Special case: single error
            msg = next(err for errs in errors.values() for err in errs)
            raise Invalid(msg)

        # Multiple errors
        msgs = []
        for category, errs in errors.items():
            if errs:
                msgs.extend(errs)
        raise Invalid('\n'.join(msgs))

    return True

def verifyObject(iface, candidate, tentative=False):
    from zope.interface.exceptions import Invalid, DoesNotImplement, BrokenImplementation, BrokenMethodImplementation
    from zope.interface.interface import Method
    from collections import defaultdict

    if not tentative and not iface.providedBy(candidate):
        raise DoesNotImplement(iface)

    errors = defaultdict(list)

    # Verifica metodi
    for name, desc in iface.namesAndDescriptions(1):
        if isinstance(desc, Method):
            # Verifica che il metodo esista
            try:
                attr = getattr(candidate, name)
            except AttributeError:
                errors['missing_methods'].append(name)
                continue

            # Verifica che sia chiamabile
            if not callable(attr):
                errors['not_callable'].append(name)
                continue

            # Verifica la firma del metodo
            try:
                from inspect import signature
                impl_sig = signature(attr)
                desc_sig = signature(desc)

                if impl_sig != desc_sig:
                    errors['wrong_signature'].append((name, str(desc_sig), str(impl_sig)))
            except ValueError:
                # Non è possibile ottenere la firma
                pass

        else:
            # Verifica attributi
            if not hasattr(candidate, name):
                errors['missing_attributes'].append(name)

    # Se non ci sono errori, restituisci True
    if not errors:
        return True

    # Gestione errori
    total_errors = sum(len(v) for v in errors.values())

    if total_errors == 1:
        # Caso speciale: un solo errore
        if errors['missing_methods']:
            raise BrokenImplementation(iface, errors['missing_methods'][0])
        if errors['not_callable']:
            raise BrokenMethodImplementation(iface, errors['not_callable'][0])
        if errors['wrong_signature']:
            name, expected, got = errors['wrong_signature'][0]
            raise BrokenMethodImplementation(iface, name, f"Expected {expected}, got {got}")
        if errors['missing_attributes']:
            raise BrokenImplementation(iface, errors['missing_attributes'][0])

    # Più errori: raccoglili tutti in un unico messaggio
    error_msg = []
    if errors['missing_methods']:
        error_msg.append(f"Missing methods: {', '.join(errors['missing_methods'])}")
    if errors['not_callable']:
        error_msg.append(f"Non-callable methods: {', '.join(errors['not_callable'])}")
    if errors['wrong_signature']:
        sig_errors = [f"{name} (expected {exp}, got {got})" for name, exp, got in errors['wrong_signature']]
        error_msg.append(f"Wrong signatures: {', '.join(sig_errors)}")
    if errors['missing_attributes']:
        error_msg.append(f"Missing attributes: {', '.join(errors['missing_attributes'])}")

    raise Invalid('\n'.join(error_msg))

def determineMetaclass(bases, explicit_mc=None):
    """
    Determina la metaclasse a partire da una o più basi e da un'eventuale __metaclass__ esplicita.
    """
    # If there's an explicit metaclass, start with that
    metaclass = explicit_mc

    # If no explicit metaclass, look through base classes
    if metaclass is None:
        if bases:
            # Get metaclasses from all base classes
            metaclasses = [type(base) for base in bases]
            # Find most derived metaclass
            metaclass = metaclasses[0]
            for mc in metaclasses[1:]:
                if issubclass(mc, metaclass):
                    metaclass = mc
                elif not issubclass(metaclass, mc):
                    raise TypeError("Incompatible metaclasses")
        else:
            # No bases and no explicit metaclass, use type
            metaclass = type

    # If explicit metaclass was provided, ensure it's compatible with base metaclasses
    else:
        for base in bases:
            if not issubclass(metaclass, type(base)):
                raise TypeError("Explicit metaclass not compatible with base metaclasses")

    return metaclass

