    import xml.etree.ElementTree as ET
    from typing import Dict

    # Try parsing as JSON first
    try:
        data = json.loads(document)
        result = {
            'subject': data.get('subject', ''),
            'aliases': data.get('aliases', []),
            'links': []
        }

        # Parse links
        for link in data.get('links', []):
            link_data = {
                'rel': link.get('rel', ''),
                'href': link.get('href', ''),
                'type': link.get('type', '')
            }
            result['links'].append(link_data)

        return result

    except json.JSONDecodeError:
        # If JSON parsing fails, try XRD format
        try:
            # Remove XML namespace to simplify parsing
            document = document.replace('xmlns="http://docs.oasis-open.org/ns/xri/xrd-1.0"', '')
            root = ET.fromstring(document)

            result = {
                'subject': root.findtext('Subject', ''),
                'aliases': [],
                'links': []
            }

            # Parse aliases
            for alias in root.findall('Alias'):
                if alias.text:
                    result['aliases'].append(alias.text)

            # Parse links
            for link in root.findall('Link'):
                link_data = {
                    'rel': link.get('rel', ''),
                    'href': link.get('href', ''),
                    'type': link.get('type', '')
                }
                result['links'].append(link_data)

            return result

        except ET.ParseError:
            raise ValueError("Invalid webfinger document format - neither JSON nor XRD")

def dict_insert(dic, val, key, *keys):
    if not keys:
        # Base case - no more nested keys, insert value directly
        dic[key] = val
        return

    # Create nested dictionary if it doesn't exist
    if key not in dic:
        dic[key] = {}
    elif not isinstance(dic[key], dict):
        # Convert existing value to dict if needed
        dic[key] = {}

    # Recursively insert into nested dictionary
    dict_insert(dic[key], val, keys[0], *keys[1:])

