        required_fields = ['field1', 'field2', 'field3']  # Esempio campi richiesti
        missing_fields = []

        for field in required_fields:
            if field not in yaml_data:
                missing_fields.append(field)

        if missing_fields:
            raise IRValidatorException(f"Campi obbligatori mancanti: {', '.join(missing_fields)}")

        return yaml_data

    except yaml.YAMLError as e:
        raise IRValidatorException(f"Errore nel parsing del file YAML: {str(e)}")
    except FileNotFoundError:
        raise IRValidatorException(f"File non trovato: {yaml_file}")
    except Exception as e:
        raise IRValidatorException(f"Errore durante la validazione: {str(e)}")

def _include_groups(self, parser_dict):
    """
    Risolve la direttiva "include dict" nei file di specifica
    """
    if not parser_dict:
        return {}

    result = {}
    for key, value in parser_dict.items():
        if isinstance(value, dict):
            if 'include' in value:
                # Get included dictionary name
                include_name = value['include']

                # Look up included dictionary in self.groups
                if include_name in self.groups:
                    included_dict = self.groups[include_name]
                    # Merge included dict with current dict
                    merged = included_dict.copy()
                    merged.update(value)
                    # Remove the include directive
                    del merged['include']
                    result[key] = merged
                else:
                    raise KeyError(f"Referenced group '{include_name}' not found")
            else:
                # Recursively process nested dictionaries
                result[key] = self._include_groups(value)
        else:
            result[key] = value

    return result

