def validate_choices_args(self, args):
    """
    Verifica se il valore degli argomenti di scelta è una delle opzioni disponibili.  

    :param args: Gli argomenti ricevuti.  
    """
    for arg_name, arg_value in args.items():
        if hasattr(self, f'_{arg_name}_choices'):
            choices = getattr(self, f'_{arg_name}_choices')
            if arg_value not in choices:
                raise ValueError(f"Invalid value '{arg_value}' for argument '{arg_name}'. "
                               f"Valid choices are: {choices}")

def validate_min_max_args(self, args):
    """
    Verifica se il valore degli argomenti è compreso tra i valori minimo e massimo.

    :param args: Gli argomenti ricevuti.
    """
    for arg_name, arg_value in args.items():
        if hasattr(self, f'min_{arg_name}') and hasattr(self, f'max_{arg_name}'):
            min_val = getattr(self, f'min_{arg_name}')
            max_val = getattr(self, f'max_{arg_name}')

            if not min_val <= arg_value <= max_val:
                raise ValueError(f"Il valore di {arg_name} deve essere compreso tra {min_val} e {max_val}")

def create_complex_argument_type(self, subcommand, type_name, option_name, spec_option):
    """
    Crea il tipo di argomento complesso.

    :param subcommand: il nome del comando
    :param type_name: il nome del tipo complesso
    :param option_name: il nome dell'opzione
    :param spec_option: le specifiche dell'opzione
    :return: l'istanza del tipo complesso
    """
    # Create a custom type class dynamically
    class ComplexType:
        def __init__(self, value):
            self.value = value

        def __str__(self):
            return str(self.value)

        @staticmethod
        def validate(value):
            # Validate based on spec_option
            if 'pattern' in spec_option:
                import re
                if not re.match(spec_option['pattern'], value):
                    raise ValueError(f"Invalid format for {option_name}")

            if 'choices' in spec_option:
                if value not in spec_option['choices']:
                    raise ValueError(f"Value must be one of: {spec_option['choices']}")

            if 'min' in spec_option:
                try:
                    if float(value) < spec_option['min']:
                        raise ValueError(f"Value must be >= {spec_option['min']}")
                except ValueError:
                    raise ValueError("Value must be a number")

            if 'max' in spec_option:
                try:
                    if float(value) > spec_option['max']:
                        raise ValueError(f"Value must be <= {spec_option['max']}")
                except ValueError:
                    raise ValueError("Value must be a number")

            return value

        def __call__(self, value):
            validated_value = self.validate(value)
            return ComplexType(validated_value)

    # Set the type name
    ComplexType.__name__ = type_name

    # Create instance
    return ComplexType()

def merge_extra_vars(vars_dict, extra_vars=None):
    """
    Estende ``vars_dict`` con ``extra-vars``

    :param vars_dict: Dizionario in cui unire le extra-vars
    :param extra_vars: Lista di extra-vars
    """
    if extra_vars is None:
        return vars_dict

    if isinstance(extra_vars, list):
        for var in extra_vars:
            if isinstance(var, dict):
                vars_dict.update(var)
    elif isinstance(extra_vars, dict):
        vars_dict.update(extra_vars)

    return vars_dict

def _convert_non_cli_args(self, parser_name, values_dict):
    """
    Converte gli argomenti nei tipi corretti modificando il parametro values_dict.

    Per impostazione predefinita, tutti i valori sono stringhe.

    :param parser_name: Il nome del comando, ad esempio main, virsh, ospd, ecc.
    :param values_dict: Il dizionario con gli argomenti
    """
    if not values_dict:
        return

    # Get parser configuration for this command
    parser_config = self.parsers.get(parser_name, {})

    # Iterate through all arguments in values_dict
    for arg_name, value in values_dict.items():
        # Skip if value is None
        if value is None:
            continue

        # Get argument type from parser config
        arg_type = parser_config.get(arg_name, {}).get('type', str)

        try:
            # Convert boolean strings
            if arg_type == bool:
                if isinstance(value, str):
                    values_dict[arg_name] = value.lower() in ('true', 't', 'yes', 'y', '1')
            # Convert numeric types
            elif arg_type in (int, float):
                values_dict[arg_name] = arg_type(value)
            # Convert lists
            elif arg_type == list and isinstance(value, str):
                values_dict[arg_name] = value.split(',')
            # Convert other types
            else:
                values_dict[arg_name] = arg_type(value)

        except (ValueError, TypeError):
            # Keep original value if conversion fails
            continue

def get_plugin_spec_flatten_dict(plugin_dir):
    """
    Crea un dizionario non annidato a partire dalle specifiche del plugin.

    :param plugin_dir: Un percorso alla directory del plugin  
    :return: Un dizionario piatto che contiene le proprietà del plugin
    """
    flattened = {}

    def flatten_dict(d, parent_key=''):
        for key, value in d.items():
            new_key = f"{parent_key}.{key}" if parent_key else key

            if isinstance(value, dict):
                flatten_dict(value, new_key)
            else:
                flattened[new_key] = value

    # Leggi il file delle specifiche
    spec_file = os.path.join(plugin_dir, 'plugin.json')
    if not os.path.exists(spec_file):
        spec_file = os.path.join(plugin_dir, 'plugin.yaml')

    if not os.path.exists(spec_file):
        raise FileNotFoundError(f"No plugin specification file found in {plugin_dir}")

    # Carica le specifiche
    with open(spec_file, 'r') as f:
        if spec_file.endswith('.json'):
            import json
            specs = json.load(f)
        else:
            import yaml
            specs = yaml.safe_load(f)

    # Appiattisci il dizionario
    flatten_dict(specs)

    return flattened

